# genai_sdk/telemetry/micro_survey.py
import httpx, os, random

SURVEY_ENDPOINT = "https://devex-survey.internal/api/response"
SAMPLE_RATE     = 0.10   # 10% of eligible events trigger a survey prompt

def maybe_prompt_micro_survey(context: str, event: str) -> None:
    """
    Call after events that are candidates for micro-survey.
    context: 'sdk_error' | 'ci_wait_exceeded' | 'first_successful_run'
    event:   a short description shown to the user
    """
    if random.random() > SAMPLE_RATE:
        return
    if not os.environ.get("GENAI_DEVEX_SURVEY_OPT_IN"):
        return   # only prompt if engineer opted in via env var

    print(f"\n[Platform DevEx] Quick question about: {event}")
    print("How much did this slow you down? [1=not at all, 5=significantly blocked me] (Enter to skip)")
    try:
        response = input("> ").strip()
        if response and response.isdigit() and 1 <= int(response) <= 5:
            httpx.post(SURVEY_ENDPOINT, json={
                "context": context,
                "event":   event,
                "score":   int(response),
            }, timeout=2.0)
    except (EOFError, KeyboardInterrupt):
        pass   # non-interactive environment or user skipped

# analysis/cluster_themes.py
# Lightweight theme clustering using keyword matching on free-text responses

import csv, collections

THEMES = {
    "documentation":   ["doc", "example", "readme", "guide", "unclear", "confusing"],
    "performance":     ["slow", "timeout", "wait", "fast", "speed", "latency"],
    "api_friction":    ["api", "interface", "sdk", "import", "version", "breaking"],
    "support":         ["response", "answer", "help", "ticket", "unresponsive"],
    "onboarding":      ["setup", "getting started", "first time", "install", "configure"],
    "eval_runner":     ["eval", "benchmark", "scorer", "test run", "dataset"],
    "quota":           ["quota", "rate limit", "429", "budget", "cost"],
}

def cluster(text: str) -> list[str]:
    text_lower = text.lower()
    return [theme for theme, keywords in THEMES.items()
            if any(kw in text_lower for kw in keywords)]

with open("responses.csv") as f:
    reader = csv.DictReader(f)
    theme_counts: dict[str, int] = collections.Counter()
    for row in reader:
        for field in ("q6_pain_point", "q7_time_saver"):
            for theme in cluster(row.get(field, "")):
                theme_counts[theme] += 1

for theme, count in theme_counts.most_common():
    print(f"{theme:20s}: {count} mentions")
